          {/* Main Overlay Container */}
          <div className="w-full h-full bg-stone-900/95 backdrop-blur-xl border-2 border-stone-700/50 rounded-3xl shadow-[0_30px_100px_rgba(0,0,0,0.8)] overflow-hidden flex flex-col relative">

